import React, { useState, useRef, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  TextField,
  IconButton,
  Avatar,
  Typography,
  Divider,
  Chip,
  List,
  ListItem,
  ListItemAvatar,
  ListItemText,
  InputAdornment,
  Menu,
  MenuItem,
  ListItemIcon,
  Badge,
} from '@mui/material';
import {
  Send,
  AttachFile,
  EmojiEmotions,
  MoreVert,
  Videocam,
  Phone,
  Search,
  FilterList,
  Block,
  Report,
  Archive,
  Delete,
} from '@mui/icons-material';
import { User, Message } from '../../types';

interface ChatWindowProps {
  currentUser: User;
  messages: Message[];
  onSendMessage: (content: string, attachments?: File[]) => void;
  onTyping?: (isTyping: boolean) => void;
  isOnline?: boolean;
  lastSeen?: string;
}

const ChatWindow: React.FC<ChatWindowProps> = ({
  currentUser,
  messages,
  onSendMessage,
  onTyping,
  isOnline = false,
  lastSeen,
}) => {
  const [message, setMessage] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [anchorEl, setAnchorEl] = useState<null | HTMLElement>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSendMessage = () => {
    if (message.trim()) {
      onSendMessage(message.trim());
      setMessage('');
      setIsTyping(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setMessage(e.target.value);
    
    if (e.target.value && !isTyping) {
      setIsTyping(true);
      onTyping?.(true);
    } else if (!e.target.value && isTyping) {
      setIsTyping(false);
      onTyping?.(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files && files.length > 0) {
      onSendMessage(message, Array.from(files));
      setMessage('');
    }
  };

  const formatTime = (dateString: string) => {
    const date = new Date(dateString);
    const now = new Date();
    const diff = now.getTime() - date.getTime();
    const minutes = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));

    if (minutes < 1) return 'Just now';
    if (minutes < 60) return `${minutes}m ago`;
    if (hours < 24) return `${hours}h ago`;
    if (days < 7) return `${days}d ago`;
    return date.toLocaleDateString();
  };

  const isConsecutiveMessage = (currentMessage: Message, previousMessage: Message) => {
    return (
      currentMessage.sender.id === previousMessage.sender.id &&
      new Date(currentMessage.createdAt).getTime() - new Date(previousMessage.createdAt).getTime() < 300000 // 5 minutes
    );
  };

  const handleMenuOpen = (event: React.MouseEvent<HTMLElement>) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  return (
    <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* Chat Header */}
      <Card sx={{ borderRadius: 0, boxShadow: 1 }}>
        <CardContent sx={{ py: 2 }}>
          <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
              <Badge
                overlap="circular"
                anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
                badgeContent={
                  <Box
                    sx={{
                      width: 12,
                      height: 12,
                      borderRadius: '50%',
                      backgroundColor: isOnline ? '#4caf50' : '#f44336',
                      border: '2px solid white',
                    }}
                  />
                }
              >
                <Avatar src={currentUser.avatar}>
                  {currentUser.firstName[0]}{currentUser.lastName[0]}
                </Avatar>
              </Badge>
              <Box>
                <Typography variant="h6">
                  {currentUser.firstName} {currentUser.lastName}
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  {isOnline ? 'Online' : lastSeen ? `Last seen ${formatTime(lastSeen)}` : 'Offline'}
                </Typography>
              </Box>
            </Box>
            <Box sx={{ display: 'flex', gap: 1 }}>
              <IconButton>
                <Search />
              </IconButton>
              <IconButton>
                <Videocam />
              </IconButton>
              <IconButton>
                <Phone />
              </IconButton>
              <IconButton onClick={handleMenuOpen}>
                <MoreVert />
              </IconButton>
            </Box>
          </Box>
        </CardContent>
      </Card>

      {/* Messages */}
      <Box
        sx={{
          flexGrow: 1,
          overflow: 'auto',
          p: 2,
          backgroundColor: '#f5f5f5',
        }}
      >
        <List>
          {messages.map((msg, index) => {
            const isCurrentUser = msg.sender.id === currentUser.id;
            const isConsecutive = index > 0 && isConsecutiveMessage(msg, messages[index - 1]);
            
            return (
              <ListItem
                key={msg.id}
                sx={{
                  flexDirection: isCurrentUser ? 'row-reverse' : 'row',
                  alignItems: 'flex-start',
                  py: 0.5,
                }}
              >
                {!isCurrentUser && !isConsecutive && (
                  <ListItemAvatar>
                    <Avatar src={msg.sender.avatar} sx={{ width: 32, height: 32 }}>
                      {msg.sender.firstName[0]}{msg.sender.lastName[0]}
                    </Avatar>
                  </ListItemAvatar>
                )}
                {!isCurrentUser && isConsecutive && (
                  <ListItemAvatar>
                    <Box sx={{ width: 32, height: 32 }} />
                  </ListItemAvatar>
                )}
                <Box
                  sx={{
                    maxWidth: '70%',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: isCurrentUser ? 'flex-end' : 'flex-start',
                  }}
                >
                  {!isConsecutive && (
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 0.5 }}>
                      <Typography variant="caption" color="text.secondary">
                        {msg.sender.firstName} {msg.sender.lastName}
                      </Typography>
                      <Typography variant="caption" color="text.secondary">
                        {formatTime(msg.createdAt)}
                      </Typography>
                    </Box>
                  )}
                  <Box
                    sx={{
                      backgroundColor: isCurrentUser ? 'primary.main' : 'white',
                      color: isCurrentUser ? 'white' : 'text.primary',
                      borderRadius: 2,
                      px: 2,
                      py: 1,
                      boxShadow: 1,
                      wordBreak: 'break-word',
                    }}
                  >
                    <Typography variant="body2">{msg.content}</Typography>
                    {msg.attachments && msg.attachments.length > 0 && (
                      <Box sx={{ mt: 1 }}>
                        {msg.attachments.map((file, fileIndex) => (
                          <Chip
                            key={fileIndex}
                            label={file.name}
                            size="small"
                            sx={{
                              backgroundColor: isCurrentUser ? 'rgba(255,255,255,0.2)' : 'grey.200',
                              color: isCurrentUser ? 'white' : 'text.primary',
                              mr: 1,
                              mb: 1,
                            }}
                          />
                        ))}
                      </Box>
                    )}
                  </Box>
                  {isConsecutive && (
                    <Typography variant="caption" color="text.secondary" sx={{ mt: 0.5 }}>
                      {formatTime(msg.createdAt)}
                    </Typography>
                  )}
                </Box>
              </ListItem>
            );
          })}
          <div ref={messagesEndRef} />
        </List>
      </Box>

      {/* Message Input */}
      <Card sx={{ borderRadius: 0, boxShadow: 1 }}>
        <CardContent sx={{ py: 2 }}>
          <TextField
            ref={inputRef}
            fullWidth
            multiline
            maxRows={4}
            placeholder="Type a message..."
            value={message}
            onChange={handleInputChange}
            onKeyPress={handleKeyPress}
            InputProps={{
              endAdornment: (
                <InputAdornment position="end">
                  <Box sx={{ display: 'flex', gap: 0.5 }}>
                    <input
                      type="file"
                      id="file-upload"
                      multiple
                      style={{ display: 'none' }}
                      onChange={handleFileUpload}
                    />
                    <label htmlFor="file-upload">
                      <IconButton component="span" size="small">
                        <AttachFile />
                      </IconButton>
                    </label>
                    <IconButton size="small">
                      <EmojiEmotions />
                    </IconButton>
                    <IconButton
                      onClick={handleSendMessage}
                      disabled={!message.trim()}
                      color="primary"
                    >
                      <Send />
                    </IconButton>
                  </Box>
                </InputAdornment>
              ),
            }}
          />
        </CardContent>
      </Card>

      {/* Context Menu */}
      <Menu
        anchorEl={anchorEl}
        open={Boolean(anchorEl)}
        onClose={handleMenuClose}
      >
        <MenuItem onClick={handleMenuClose}>
          <ListItemIcon>
            <Search fontSize="small" />
          </ListItemIcon>
          <ListItemText>Search Messages</ListItemText>
        </MenuItem>
        <MenuItem onClick={handleMenuClose}>
          <ListItemIcon>
            <FilterList fontSize="small" />
          </ListItemIcon>
          <ListItemText>Filter Messages</ListItemText>
        </MenuItem>
        <MenuItem onClick={handleMenuClose}>
          <ListItemIcon>
            <Archive fontSize="small" />
          </ListItemIcon>
          <ListItemText>Archive Chat</ListItemText>
        </MenuItem>
        <MenuItem onClick={handleMenuClose}>
          <ListItemIcon>
            <Block fontSize="small" />
          </ListItemIcon>
          <ListItemText>Block User</ListItemText>
        </MenuItem>
        <MenuItem onClick={handleMenuClose}>
          <ListItemIcon>
            <Report fontSize="small" />
          </ListItemIcon>
          <ListItemText>Report</ListItemText>
        </MenuItem>
        <MenuItem onClick={handleMenuClose}>
          <ListItemIcon>
            <Delete fontSize="small" />
          </ListItemIcon>
          <ListItemText>Delete Chat</ListItemText>
        </MenuItem>
      </Menu>
    </Box>
  );
};

export default ChatWindow;
